#include <stdio.h>
#include <stdlib.h>

int *leftChild;
int *rightChild;
int *isChild;

int height(int node) {
    if (node == 0) return -1; // null contributes -1 so leaf becomes 0
    int hl = height(leftChild[node]);
    int hr = height(rightChild[node]);
    return (hl > hr ? hl : hr) + 1;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        leftChild = (int*)calloc(N + 1, sizeof(int));
        rightChild = (int*)calloc(N + 1, sizeof(int));
        isChild = (int*)calloc(N + 1, sizeof(int));
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            if (dir == 'L') leftChild[p] = c; else rightChild[p] = c;
            isChild[c] = 1;
        }
        int root = 1;
        for (int i = 1; i <= N; ++i) if (!isChild[i]) { root = i; break; }
        int ans = height(root);
        printf("%d\n", ans);
        free(leftChild);
        free(rightChild);
        free(isChild);
    }
    return 0;
}

