#include <bits/stdc++.h>
using namespace std;

int dfsHeight(int node, const vector<int>& left, const vector<int>& right) {
    if (node == 0) return -1; // null contributes -1 so leaf becomes 0
    int hl = dfsHeight(left[node], left, right);
    int hr = dfsHeight(right[node], left, right);
    return max(hl, hr) + 1;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
