import java.io.*;
import java.util.*;

public class Main {
    static int height(int node, int[] left, int[] right) {
        if (node == 0) return -1; // null contributes -1
        int hl = height(left[node], left, right);
        int hr = height(right[node], left, right);
        return Math.max(hl, hr) + 1;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] left = new int[N + 1];
            int[] right = new int[N + 1];
            boolean[] isChild = new boolean[N + 1];
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                if (dir == 'L') left[p] = c; else right[p] = c;
                isChild[c] = true;
            }
            int root = 1;
            for (int i = 1; i <= N; i++) if (!isChild[i]) { root = i; break; }
            int ans = height(root, left, right);
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def height(node, left, right):
    if node == 0:
        return -1  # null contributes -1 so leaf becomes 0
    hl = height(left[node], left, right)
    hr = height(right[node], left, right)
    return max(hl, hr) + 1

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(T):
        N = int(data[idx].strip()); idx += 1
        left = [0] * (N + 1)
        right = [0] * (N + 1)
        is_child = [False] * (N + 1)
        for __ in range(N - 1):
            pi, ci, Ri = data[idx].split(); idx += 1
            pi = int(pi); ci = int(ci)
            if Ri == 'L':
                left[pi] = ci
            else:
                right[pi] = ci
            is_child[ci] = True
        root = 1
        for i in range(1, N + 1):
            if not is_child[i]:
                root = i
                break
        out_lines.append(str(height(root, left, right)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

